example.good:
def execute_shieldacker: Entity, target: Entity) -> Dict[str, Any]:
    # Check cooldown
    if attacker.shield_bash_cooldown > 0:
        return {"success": False, "reason": "on_cooldown", "cooldown": attacker.shield_bash_cooldown}
    # Apply stun
    target.stun_turns = 1
    attacker.shield_bash_cooldown = 3
    return {"success": True, "stun_applied": True, "cooldown_set": 3}

